<script setup lang="ts">
import { computed,onMounted,reactive,ref } from 'vue'
import { ElMessage,ElMessageBox } from 'element-plus'
import { Download,Edit,Plus,Refresh,Setting,User } from '@element-plus/icons-vue'
import { listDocuments,type GeologicalDocument } from '@/api/documents'
import { deleteUser,downloadExport,listLlmConfigs,listLogs,listTasks,listUsers,pushToOneMap,restoreDemoData,saveLlmConfig,saveUser,type AdminUser,type LlmConfig,type SystemLog,type UserInput } from '@/api/admin'

type Tab='exports'|'users'|'tasks'|'models'|'logs'
const tab=ref<Tab>('exports'),loading=ref(true),users=ref<AdminUser[]>([]),tasks=ref<GeologicalDocument[]>([]),configs=ref<LlmConfig[]>([]),logs=ref<SystemLog[]>([]),documents=ref<GeologicalDocument[]>([])
const dialog=ref(false),editing=ref<number>(),userForm=reactive<UserInput>({username:'',password:'',displayName:'',role:'USER',enabled:true})
const exportForm=reactive({documentId:undefined as number|undefined,format:'xlsx',dataset:'entities'}),exporting=ref(false)
const configForms=ref<Array<LlmConfig&{apiKey?:string}>>([])
const completedTasks=computed(()=>tasks.value.filter(t=>t.graphStatus==='COMPLETED').length)
const failedTasks=computed(()=>tasks.value.filter(t=>[t.status,t.entityStatus,t.knowledgeStatus,t.spatialStatus,t.graphStatus].includes('FAILED')).length)
const tabs:[Tab,string][]=[['exports','成果导出'],['users','用户管理'],['tasks','任务管理'],['models','模型配置'],['logs','调用日志']]
async function load(){loading.value=true;try{const[us,ts,cs,ls,docs]=await Promise.all([listUsers(),listTasks(),listLlmConfigs(),listLogs(),listDocuments({page:1,size:100,status:'PARSED'})]);users.value=us;tasks.value=ts;configs.value=cs;configForms.value=cs.map(c=>({...c,apiKey:''}));logs.value=ls;documents.value=docs.records;exportForm.documentId=docs.records[0]?.id}catch(e){ElMessage.error(message(e))}finally{loading.value=false}}
function openUser(user?:AdminUser){editing.value=user?.id;Object.assign(userForm,user?{username:user.username,password:'',displayName:user.displayName,role:user.role,enabled:user.enabled}:{username:'',password:'',displayName:'',role:'USER',enabled:true});dialog.value=true}
async function submitUser(){try{await saveUser(userForm,editing.value);ElMessage.success('用户已保存');dialog.value=false;users.value=await listUsers()}catch(e){ElMessage.error(message(e))}}
async function removeUser(user:AdminUser){try{await ElMessageBox.confirm(`确认删除用户“${user.displayName}”？`,'删除用户',{type:'warning'});await deleteUser(user.id);users.value=await listUsers()}catch(e){if(e instanceof Error)ElMessage.error(message(e))}}
async function saveConfig(form:LlmConfig&{apiKey?:string}){try{await saveLlmConfig({provider:form.provider,baseUrl:form.baseUrl,modelName:form.modelName,apiKey:form.apiKey||undefined,temperature:form.temperature,promptTemplate:form.promptTemplate,enabled:form.enabled});ElMessage.success(`${form.provider} 配置已保存并应用`);configs.value=await listLlmConfigs();configForms.value=configs.value.map(c=>({...c,apiKey:''}))}catch(e){ElMessage.error(message(e))}}
async function runExport(){if(!exportForm.documentId)return;exporting.value=true;try{await downloadExport(exportForm.documentId,exportForm.format,exportForm.dataset);ElMessage.success('成果文件已生成')}catch(e){ElMessage.error(message(e))}finally{exporting.value=false}}
async function restoreDemo(){try{const doc=await restoreDemoData();ElMessage.success(`已恢复标准演示资料：${doc.name}，解析任务已启动`);await load()}catch(e){ElMessage.error(message(e))}}
async function pushOneMap(){if(!exportForm.documentId)return;try{const result=await pushToOneMap(exportForm.documentId);ElMessage.success(result.message)}catch(e){ElMessage.error(message(e))}}
function stage(task:GeologicalDocument){const items=[task.status,task.entityStatus,task.knowledgeStatus,task.spatialStatus,task.graphStatus];if(items.includes('FAILED'))return'FAILED';if(task.graphStatus==='COMPLETED')return'COMPLETED';if(items.some(v=>v==='PARSING'||v==='EXTRACTING'||v==='SYNCING'))return'RUNNING';return'PENDING'}
function message(e:unknown){return e instanceof Error?e.message:'操作失败'}onMounted(load)
</script>

<template><div class="admin-page" v-loading="loading"><header class="admin-header"><div><span>Phase 8 · DELIVERY CONTROL</span><h1>成果与系统控制台</h1><p>在一个可审计的工作台完成成果交付、模型配置与运行治理。</p></div><div><b>{{users.length}}</b><small>用户</small><b>{{completedTasks}}</b><small>完整任务</small><b>{{failedTasks}}</b><small>异常</small></div></header><nav class="admin-tabs"><button v-for="item in tabs" :key="item[0]" type="button" :class="{active:tab===item[0]}" @click="tab=item[0]">{{item[1]}}</button></nav><main class="admin-content"><section v-if="tab==='exports'" class="export-studio"><div><span>RESEARCH PACKAGE</span><h2>结构化成果导出</h2><p>Excel 汇总四类成果；CSV 可选择单类数据；JSON 保留完整结构；GeoJSON 可直接进入 GIS 软件。</p></div><div class="export-form"><label>来源资料<el-select v-model="exportForm.documentId"><el-option v-for="doc in documents" :key="doc.id" :label="doc.name" :value="doc.id"/></el-select></label><label>文件格式<el-select v-model="exportForm.format"><el-option label="Excel 工作簿" value="xlsx"/><el-option label="CSV 表格" value="csv"/><el-option label="JSON 全量包" value="json"/><el-option label="GeoJSON 空间包" value="geojson"/></el-select></label><label v-if="exportForm.format==='csv'">数据集<el-select v-model="exportForm.dataset"><el-option label="实体" value="entities"/><el-option label="属性" value="attributes"/><el-option label="关系" value="relations"/><el-option label="空间对象" value="spatial"/></el-select></label><button type="button" :disabled="exporting" @click="runExport"><el-icon><Download/></el-icon>{{exporting?'正在生成…':'生成并下载'}}</button></div><div class="format-grid"><article v-for="item in [['XLSX','四张工作表'],['CSV','UTF-8 / 可筛选'],['JSON','完整证据结构'],['GEOJSON','FeatureCollection']]" :key="item[0]"><strong>{{item[0]}}</strong><span>{{item[1]}}</span></article></div></section><section v-else-if="tab==='users'" class="admin-panel"><header><div><span>ACCESS CONTROL</span><h2>系统用户</h2></div><button type="button" @click="openUser()"><el-icon><Plus/></el-icon>新增用户</button></header><div class="user-grid"><article v-for="item in users" :key="item.id"><el-icon><User/></el-icon><div><strong>{{item.displayName}}</strong><small>@{{item.username}}</small></div><span :class="item.role.toLowerCase()">{{item.role}}</span><em :class="{off:!item.enabled}">{{item.enabled?'启用':'停用'}}</em><button type="button" @click="openUser(item)"><el-icon><Edit/></el-icon></button><button type="button" @click="removeUser(item)">删除</button></article></div></section><section v-else-if="tab==='tasks'" class="admin-panel"><header><div><span>PIPELINE MONITOR</span><h2>全流程任务</h2></div><button type="button" @click="load"><el-icon><Refresh/></el-icon>刷新</button></header><div class="task-table"><header><span>资料</span><span>解析</span><span>实体</span><span>知识</span><span>空间</span><span>图谱</span><span>总体</span></header><article v-for="task in tasks" :key="task.id"><strong>{{task.name}}</strong><span>{{task.status}}</span><span>{{task.entityStatus||'PENDING'}}</span><span>{{task.knowledgeStatus||'PENDING'}}</span><span>{{task.spatialStatus||'PENDING'}}</span><span>{{task.graphStatus||'PENDING'}}</span><b :class="stage(task).toLowerCase()">{{stage(task)}}</b></article></div></section><section v-else-if="tab==='models'" class="admin-panel"><header><div><span>MODEL RUNTIME</span><h2>LLM 配置</h2></div><p>API Key 保存后不回显；启用配置会实时推送至 AI 服务。</p></header><div class="model-grid"><article v-for="form in configForms" :key="form.provider"><header><strong>{{form.provider}}</strong><span :class="{ready:form.keyConfigured}">{{form.keyConfigured?'KEY 已配置':'等待 KEY'}}</span></header><label>API 地址<input v-model="form.baseUrl"/></label><label>模型名称<input v-model="form.modelName"/></label><label>API Key<input v-model="form.apiKey" type="password" placeholder="留空则保持原密钥"/></label><label>Temperature <input v-model.number="form.temperature" type="number" min="0" max="2" step="0.1"/></label><label>Prompt 模板<textarea v-model="form.promptTemplate" rows="4" placeholder="作为系统提示词前缀"></textarea></label><div><el-switch v-model="form.enabled" active-text="启用"/><button type="button" @click="saveConfig(form)"><el-icon><Setting/></el-icon>保存并应用</button></div></article></div></section><section v-else class="admin-panel"><header><div><span>AUDIT TRAIL</span><h2>AI 调用日志</h2></div><button type="button" @click="listLogs().then(v=>logs=v)"><el-icon><Refresh/></el-icon>刷新</button></header><div class="log-table"><header><span>时间</span><span>功能</span><span>模型</span><span>状态</span><span>耗时</span><span>异常</span></header><article v-for="log in logs" :key="log.id"><span>{{new Date(log.createTime).toLocaleString()}}</span><strong>{{log.functionName||log.action}}</strong><span>{{log.model||log.provider||'—'}}</span><b :class="log.status.toLowerCase()">{{log.status}}</b><span>{{log.elapsedMs??'—'}} ms</span><em>{{log.errorMessage||'—'}}</em></article></div></section></main><el-dialog v-model="dialog" :title="editing?'编辑用户':'新增用户'" width="min(520px,92vw)"><el-form label-position="top"><el-form-item label="用户名"><el-input v-model="userForm.username"/></el-form-item><el-form-item label="显示名称"><el-input v-model="userForm.displayName"/></el-form-item><el-form-item :label="editing?'新密码（留空不修改）':'密码'"><el-input v-model="userForm.password" type="password"/></el-form-item><el-form-item label="角色"><el-select v-model="userForm.role"><el-option label="管理员" value="ADMIN"/><el-option label="普通用户" value="USER"/></el-select></el-form-item><el-switch v-model="userForm.enabled" active-text="启用账号"/></el-form><template #footer><button type="button" class="admin-secondary" @click="dialog=false">取消</button><button type="button" class="admin-primary" @click="submitUser">保存</button></template></el-dialog></div></template>

<style scoped>
.admin-page{padding:30px;background:#ebe7dc;min-height:calc(100vh - 82px);color:#153c35}.admin-header{display:flex;justify-content:space-between;gap:24px}.admin-header span,.admin-panel header span,.export-studio>div>span{font:700 10px ui-monospace;letter-spacing:.18em;color:#b56b32}.admin-header h1{margin:7px 0;font:600 36px Georgia}.admin-header p{margin:0;color:#63746d}.admin-header>div:last-child{display:grid;grid-template-columns:repeat(3,auto);gap:4px 18px;align-content:center;text-align:right}.admin-header b{font:27px Georgia;color:#b45e2f}.admin-header small{grid-row:2}.admin-tabs{display:flex;margin-top:24px;border-bottom:1px solid #b9b2a3}.admin-tabs button{border:0;background:transparent;padding:13px 22px;color:#68766f}.admin-tabs button.active{background:#123d36;color:white}.admin-content{margin-top:18px}.export-studio{background:#123d36;color:#edf0e8;display:grid;grid-template-columns:1fr 1fr;gap:32px;padding:38px}.export-studio h2,.admin-panel h2{font:600 29px Georgia;margin:6px 0}.export-studio p{color:#afc0b9;line-height:1.7}.export-form{display:grid;gap:13px}.export-form label,.model-grid label{display:grid;gap:6px;font-size:11px;letter-spacing:.08em}.export-form button,.admin-panel>header button,.model-grid button{border:0;background:#e99a4c;color:#153c35;padding:12px 16px;font-weight:700}.format-grid{grid-column:1/-1;display:grid;grid-template-columns:repeat(4,1fr);border-top:1px solid #ffffff24;padding-top:24px}.format-grid article{display:grid;border-right:1px solid #ffffff24;padding:4px 18px}.format-grid strong{font:24px Georgia;color:#eca159}.format-grid span{font-size:11px;color:#aebdb7}.admin-panel{background:#f6f2e9;border:1px solid #d1c9ba;padding:24px}.admin-panel>header{display:flex;justify-content:space-between;align-items:center;margin-bottom:18px}.admin-panel>header h2{margin:5px 0}.admin-panel>header p{font-size:12px;color:#728077}.user-grid{display:grid;gap:8px}.user-grid article{display:grid;grid-template-columns:36px 1fr 80px 70px 40px 55px;align-items:center;background:white;border:1px solid #ded7cb;padding:13px}.user-grid article>svg{font-size:24px;color:#397063}.user-grid div{display:grid}.user-grid small{color:#819087}.user-grid span,.user-grid em{font:11px ui-monospace}.user-grid span.admin{color:#a8582d}.user-grid em{color:#32805e}.user-grid em.off{color:#a3453d}.user-grid button{border:0;background:transparent;color:#765744}.task-table>header,.task-table article{display:grid;grid-template-columns:minmax(220px,2fr) repeat(6,1fr);gap:10px;padding:11px;border-bottom:1px solid #ddd5c7;align-items:center;font-size:12px}.task-table>header{font:700 10px ui-monospace;color:#8b7960}.task-table article b,.log-table b{font:10px ui-monospace}.completed,.success{color:#23805a}.failed{color:#b44539}.running{color:#bd702e}.model-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}.model-grid article{background:white;border:1px solid #d9d1c3;padding:20px;display:grid;gap:12px}.model-grid article>header,.model-grid article>div{display:flex;justify-content:space-between;align-items:center}.model-grid article>header strong{font:24px Georgia;text-transform:capitalize}.model-grid article>header span{font:10px ui-monospace;color:#a55238}.model-grid article>header span.ready{color:#2a7b5c}.model-grid input,.model-grid textarea{border:1px solid #c9c0b1;background:#f8f5ef;padding:10px;font:13px inherit}.log-table>header,.log-table article{display:grid;grid-template-columns:170px 1.5fr 1fr 80px 80px 1.5fr;gap:10px;padding:11px;border-bottom:1px solid #ddd5c7;align-items:center;font-size:11px}.log-table>header{font:700 10px ui-monospace;color:#8b7960}.log-table em{overflow:hidden;text-overflow:ellipsis}.admin-primary,.admin-secondary{border:0;padding:10px 18px}.admin-primary{background:#d9813d;color:white}.admin-secondary{background:#ddd5c8}@media(max-width:850px){.admin-page{padding:14px}.admin-header{display:block}.admin-header>div:last-child{justify-content:start;text-align:left;margin-top:14px}.admin-tabs{overflow:auto}.admin-tabs button{white-space:nowrap}.export-studio{grid-template-columns:1fr;padding:22px}.format-grid{grid-template-columns:repeat(2,1fr);gap:16px}.model-grid{grid-template-columns:1fr}.task-table,.log-table{overflow:auto}.task-table>header,.task-table article{min-width:850px}.log-table>header,.log-table article{min-width:780px}.user-grid article{grid-template-columns:30px 1fr 60px 50px}.user-grid article button{grid-column:auto}.admin-panel{padding:14px}}
</style>
